#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int curr = 0;
        printf("%d", curr);
        for (int i = 1; i < N; i++) {
            int next = curr ^ (1 << (i - 1));
            if (next >= N) {
                printf(" -1");
                break;
            }
            printf(" %d", next);
            curr = next;
        }
        printf("\n");
    }
    return 0;
}

