code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int curr = 0;
            System.out.print(curr);
            for (int i = 1; i < N; i++) {
                int next = curr ^ (1 << (i - 1));
                if (next >= N) {
                    System.out.print(" -1");
                    break;
                }
                System.out.print(" " + next);
                curr = next;
            }
            System.out.println();
        }
    }
}

