const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    let curr = 0;
    process.stdout.write(curr.toString());
    for (let j = 1; j < N; j++) {
        let next = curr ^ (1 << (j - 1));
        if (next >= N) {
            process.stdout.write(' -1');
            break;
        }
        process.stdout.write(' ' + next.toString());
        curr = next;
    }
    process.stdout.write('\n');
}

